  ('elementary-10ced7e2-moex-00771', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於刑法第136條聚眾妨害公務罪構成要件之敘述，何者正確？', '["行為主體限於公務員執行職務之相對人", "行為地限於公共場所或公眾得出入之場所", "聚集人數須達5人以上", "首謀及下手實施強暴脅迫，因而致公務員於死或重傷，與傷害致死或傷害致重傷罪，數罪併罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00772', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於嚴格證明法則之敘述，何者錯誤？', '["嚴格證明與自由證明並不相同", "嚴格證明法則涉及證據能力及有無經合法調查證據之程序", "犯罪事實存在之認定需要嚴格之證明", "自由證明與自由心證之意義相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00773', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '被告以外之人於審判外之書面或言詞陳述，其有無證據能力之判斷，應依何種法則判斷之？', '["自白法則", "傳聞法則", "自由心證法則", "意見法則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00774', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依刑事訟法第27條規定，被告或犯罪嫌疑人得隨時選任辯護人，不包括下列何種情形？', '["受司法警察調查時", "法院審理準備程序", "受上級長官調查時", "移送檢察官調查時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00775', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於貪污治罪條例相關法條之敘述，何者錯誤？', '["對於公務員違背職務之行為，要求、期約或收受賄賂或其他不正利益者，構成犯罪", "對於公務員職務上之行為，要求、期約或收受賄賂或其他不正利益者，不構成犯罪", "對於主管或監督之事務，明知違背法令等規定，直接或間接圖自己或其他私人不法利益，因而獲得利 益者，構成犯罪", "對於非主管或監督之事務，明知違背法令等規定，利用職權機會或身分圖自己或其他私人不法利益， 因而獲得利益者，構成犯罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00776', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '甲犯侵占罪，尚未被發覺，妻子乙為庇護甲而出面向警方表示係其犯罪，乙是否符合刑法自首要件？', '["不符合，因警方並非偵查機關，向警方自首，於法未合", "符合，因犯罪既尚未被發覺，乙出面向警方坦承犯行，當屬自首", "不符合，因乙非侵占罪行為人，乙自無自首問題", "符合，因可以轉換成乙所犯頂替罪之自首"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00777', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於刑法上之故意犯與過失犯，下列敘述何者正確？', '["行為非出於故意者，即係出於過失", "間接故意犯與有認識過失犯之罪質相當", "刑法以處罰故意犯為原則，但過失犯情節嚴重者，仍應與故意犯同視", "過失犯之處罰以法律有明文者為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00778', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列有關刑法第138條侵害公務上掌管文書物品罪之敘述，何者錯誤？', '["甲收到法院寄發之傳票後，將之撕毀，甲成立本罪", "甲撕毀警員乙依法制作之談話筆錄，甲成立本罪", "甲與警員乙發生拉扯，致乙所穿制服毀損，甲不成立本罪", "警員乙將經扣押之物交由該物之所有權人甲暫時保管，甲故意將之毀損，甲成立本罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00779', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '刑法第17條因犯罪致發生一定之結果，而有加重其刑之規定者，如行為人不能預見其發生時，不適用之。 依實務見解，下列敘述何者錯誤？', '["必須行為人主觀上有預見結果發生", "本條在學理上稱為加重結果犯", "必須刑法條文有特別規定才有適用", "基礎犯罪與發生結果間須具備因果關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00780', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '行政程序法第3條第3項明列特定事項不適用該法之程序規定，下列何種行為即屬該法所定排除之事項？', '["內政部移民署依法禁止本國人出境", "高雄市警察局員警依據集會遊行法規定命令群眾立即解散", "國防部將部隊連級主官調任為內部單位參謀", "私立大學依據該校規定對特定學生為記過處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
